import{_ as e,o,c as a,a2 as i}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Capy — Tool System","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/capy/tool-system.md","filePath":"research/agents/capy/tool-system.md"}'),n={name:"research/agents/capy/tool-system.md"};function s(r,t,l,d,c,u){return o(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="capy-—-tool-system" tabindex="-1">Capy — Tool System <a class="header-anchor" href="#capy-—-tool-system" aria-label="Permalink to &quot;Capy — Tool System&quot;">​</a></h1><blockquote><p>Model-agnostic platform with VM-based execution and GitHub integration. Detailed tool internals are not publicly available.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Capy&#39;s tool system operates differently from open-source terminal agents. Rather than exposing a set of named tools (Read, Edit, Bash, Grep) to a single agent, Capy splits capabilities between two agents with hard boundaries — Captain gets read-only exploration tools, Build gets full execution tools.</p><p>Because Capy is a closed-source commercial product, the exact tool definitions and internal APIs are not publicly documented. What follows is reconstructed from blog posts, marketing materials, and observable behavior.</p><h2 id="model-agnostic-design" tabindex="-1">Model-Agnostic Design <a class="header-anchor" href="#model-agnostic-design" aria-label="Permalink to &quot;Model-Agnostic Design&quot;">​</a></h2><p>Capy&#39;s most notable tool-layer decision is <strong>model agnosticism</strong>. The platform supports multiple LLM providers:</p><table tabindex="0"><thead><tr><th>Provider</th><th>Model</th><th>Notes</th></tr></thead><tbody><tr><td>Anthropic</td><td>Claude Opus 4.6</td><td>Best benchmark results (Terminal-Bench #7)</td></tr><tr><td>OpenAI</td><td>GPT-5.3 Codex</td><td>Code-optimized model</td></tr><tr><td>Google</td><td>Gemini 3 Pro</td><td>Large context window</td></tr><tr><td>xAI</td><td>Grok 4 Fast</td><td>Speed-optimized</td></tr><tr><td>Moonshot</td><td>Kimi K2</td><td>—</td></tr><tr><td>Zhipu</td><td>GLM 4.7</td><td>—</td></tr><tr><td>Alibaba</td><td>Qwen 3 Coder</td><td>Code-optimized</td></tr></tbody></table><p>Users can choose which model to use per task, enabling cost/quality tradeoffs. It&#39;s not publicly documented whether Captain and Build can use different models independently.</p><h2 id="captain-s-tool-set-planning-phase" tabindex="-1">Captain&#39;s Tool Set (Planning Phase) <a class="header-anchor" href="#captain-s-tool-set-planning-phase" aria-label="Permalink to &quot;Captain&#39;s Tool Set (Planning Phase)&quot;">​</a></h2><p>Captain has <strong>read-only</strong> capabilities:</p><ul><li><strong>Codebase reading</strong>: Can explore files, directory structures, and understand code patterns</li><li><strong>Research</strong>: Can investigate documentation and context relevant to the task</li><li><strong>User interaction</strong>: Can ask the user clarifying questions in a conversational loop</li><li><strong>Spec writing</strong>: Produces a structured specification as output</li></ul><p><strong>Hard restrictions</strong>: Captain cannot write files, run terminal commands, or interact with git. These restrictions are enforced at the platform level, not just via prompt instructions.</p><h2 id="build-s-tool-set-execution-phase" tabindex="-1">Build&#39;s Tool Set (Execution Phase) <a class="header-anchor" href="#build-s-tool-set-execution-phase" aria-label="Permalink to &quot;Build&#39;s Tool Set (Execution Phase)&quot;">​</a></h2><p>Build has <strong>full execution</strong> capabilities within a sandboxed Ubuntu VM:</p><ul><li><strong>File editing</strong>: Create, modify, and delete files in the codebase</li><li><strong>Terminal execution</strong>: Full shell access with sudo privileges</li><li><strong>Dependency management</strong>: Install packages, run build tools</li><li><strong>Test execution</strong>: Run test suites and observe results</li><li><strong>Git operations</strong>: Commit changes, create branches (via worktrees)</li><li><strong>PR creation</strong>: Open pull requests on GitHub</li></ul><p><strong>Hard restrictions</strong>: Build cannot ask the user questions or request clarification. It must work from the spec alone.</p><h2 id="github-integration" tabindex="-1">GitHub Integration <a class="header-anchor" href="#github-integration" aria-label="Permalink to &quot;GitHub Integration&quot;">​</a></h2><p>Capy integrates directly with GitHub for the full development lifecycle:</p><ul><li><strong>PR Management</strong>: Build agent can create and update pull requests</li><li><strong>Code Review</strong>: Review and discuss code within the Capy interface</li><li><strong>Issue Tracking</strong>: Track and reference GitHub issues from tasks</li><li><strong>Branch Management</strong>: Automatic worktree creation for branch isolation</li></ul><h2 id="execution-environment" tabindex="-1">Execution Environment <a class="header-anchor" href="#execution-environment" aria-label="Permalink to &quot;Execution Environment&quot;">​</a></h2><p>Each task runs in its own <strong>sandboxed Ubuntu VM</strong>:</p><ul><li>Full operating system environment</li><li>Sudo access for the Build agent</li><li>Isolated from other tasks and users</li><li>Network access for package managers and external APIs</li><li>Git worktree for branch isolation</li></ul><p>This is more heavyweight than the sandboxing used by terminal agents (which typically use filesystem restrictions or Docker containers). Each Capy task gets a full VM, which enables true parallel execution without resource contention.</p><h2 id="what-s-not-publicly-known" tabindex="-1">What&#39;s Not Publicly Known <a class="header-anchor" href="#what-s-not-publicly-known" aria-label="Permalink to &quot;What&#39;s Not Publicly Known&quot;">​</a></h2><ul><li>Exact tool definitions and function signatures</li><li>How tool calls are formatted and parsed per model provider</li><li>Whether there&#39;s a tool correction or retry mechanism</li><li>MCP (Model Context Protocol) support status</li><li>Rate limiting or resource quotas per VM</li><li>How the platform handles tool failures during Build execution</li><li>Whether Build has access to web browsing or external documentation tools</li></ul>',26)])])}const g=e(n,[["render",s]]);export{p as __pageData,g as default};
